import type PopupTemplate from "../../PopupTemplate.js";

/**
 * The return object of the [getTemplates()](https://developers.arcgis.com/javascript/latest/references/core/smartMapping/popup/templates/#getTemplates) method.
 *
 * @since 5.0
 */
export interface Templates {
  /**
   * Includes the primary PopupTemplate suggested for the input layer.
   *
   * @since 5.0
   */
  primaryTemplate: Template;
  /**
   * Includes secondary PopupTemplates that may be applied to the input layer.
   *
   * @since 5.0
   */
  secondaryTemplates: Template[];
}

/**
 * Defines a suggested PopupTemplate with a given name and title describing the content
 * and purpose of the PopupTemplate.
 *
 * @since 5.0
 */
export interface Template {
  /**
   * The name of the auto-generated PopupTemplate.
   *   This can be used in the UI of web map authoring apps.
   *
   * @since 5.0
   */
  name: string;
  /**
   * The title of the PopupTemplate.
   *
   * @since 5.0
   */
  title: string;
  /**
   * The suggested PopupTemplate.
   *
   * @since 5.0
   */
  value: PopupTemplate;
}